import 'dart:async'; import 'package:injectable/injectable.dart'; @injectable class SessionTimer { final _ctrl = StreamController<Duration>.broadcast(); Timer? _timer; Duration _elapsed = Duration.zero; Stream<Duration> get stream => _ctrl.stream; Duration get elapsed => _elapsed; void start() { _timer = Timer.periodic(const Duration(seconds: 1), (_) { _elapsed += const Duration(seconds: 1); _ctrl.add(_elapsed); }); } void stop() { _timer?.cancel(); _timer = null; } void reset() { stop(); _elapsed = Duration.zero; } void dispose() { stop(); _ctrl.close(); } }